import{_ as e,o as t,c as i,ag as n}from"./chunks/framework.DUza98OV.js";const c=JSON.parse('{"title":"技术成长方法论","description":"","frontmatter":{},"headers":[],"relativePath":"thinking/engineering-growth.md","filePath":"thinking/engineering-growth.md","lastUpdated":1776563785000}'),r={name:"thinking/engineering-growth.md"};function o(l,a,h,s,d,p){return t(),i("div",null,[...a[0]||(a[0]=[n('<h1 id="技术成长方法论" tabindex="-1">技术成长方法论 <a class="header-anchor" href="#技术成长方法论" aria-label="Permalink to &quot;技术成长方法论&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>工作几年后，为什么很多工程师会感觉自己在重复业务，却很难建立真正稳定的技术成长曲线？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p>技术成长停滞往往不是因为工作不够忙，而是缺少系统化沉淀。很多经验只停留在“做过”，没有被总结成可复用的方法。想要持续成长，就要把线上问题、性能优化、架构演进和项目复盘逐步整理成自己的知识库。</p><p>另外，成长不只来自广度，也来自深度。每隔一段时间选一个主题深挖，例如 JVM、数据库或分布式事务，再把原理和实践连接起来，才能真正形成长期竞争力。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>成长的关键是复盘和知识沉淀。</li><li>业务经验需要抽象成方法论。</li><li>广度帮助协作，深度决定上限。</li><li>长期输出是检验理解程度的最好方式。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>技术成长不是靠焦虑推动，而是靠持续输入、真实实践和结构化输出慢慢积累起来的。</p>',10)])])}const u=e(r,[["render",o]]);export{c as __pageData,u as default};
